      <Row justify="center" align="center" css={{ mt: "100px" }}>
        <Text h1 css={{ mr: "10px" }}>
          I'm
        </Text>
        <Text
          h1
          css={{
            textGradient: "45deg, $pink600 -20%, $purple600 100%",
